{
  "learning_outcomes": [
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–1: Electric Charges and Fields",
      "topic": "Electrostatics: Fields, Potentials, and Capacitance",
      "outcomes": [
        "Apply Coulomb's Law and the superposition principle to calculate forces between point charges.",
        "Use Gauss's Theorem to determine electric fields for symmetric charge distributions (wire, plane, shell).",
        "Calculate electric potential and energy for various configurations including dipoles."
      ]
    },
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–2: Electrostatic Potential and Capacitance",
      "topic": "Capacitors and Dielectrics",
      "outcomes": [
        "Analyze the effect of dielectrics on electric fields and capacitor performance (capacitance increase).",
        "Calculate equivalent capacitance for complex networks in series and parallel."
      ]
    },
    {
      "unit_name": "Unit-II Current Electricity",
      "chapter_name": "Chapter–3: Current Electricity",
      "topic": "Current Electricity Fundamentals",
      "outcomes": [
        "Relate electric current to microscopic parameters (drift velocity, mobility).",
        "Analyze V-I characteristics for linear and non-linear components."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–4: Moving Charges and Magnetism",
      "topic": "Magnetic Effects of Moving Charges",
      "outcomes": [
        "Apply the Biot-Savart Law to calculate magnetic fields from current loops.",
        "Use Ampere's Circuital Law for infinite wires and solenoids."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–5: Magnetism and Matter",
      "topic": "Magnetism in Matter",
      "outcomes": [
        "Distinguish between para-, dia-, and ferro-magnetic substances based on their properties."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–6: Electromagnetic Induction",
      "topic": "Electromagnetic Induction and AC Circuits",
      "outcomes": [
        "Apply Faraday's Law and Lenz's Law to determine induced EMF and current direction."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–7: Alternating Current",
      "topic": "Alternating Current Analysis",
      "outcomes": [
        "Analyze phasor diagrams for series LCR circuits to determine phase differences."
      ]
    },
    {
      "unit_name": "Unit–V Electromagnetic Waves",
      "chapter_name": "Chapter–8: Electromagnetic Waves",
      "topic": "Electromagnetic Waves and Spectrum",
      "outcomes": [
        "Explain the generation of EM waves via changing electric/magnetic fields."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–9: Ray Optics and Optical Instruments",
      "topic": "Ray Optics and Optical Instruments",
      "outcomes": [
        "Apply mirror formulae and lens maker's formula to solve image formation problems."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–10: Wave Optics",
      "topic": "Wave Optics: Interference and Diffraction",
      "outcomes": [
        "Apply the concept of superposition to explain constructive and destructive interference."
      ]
    },
    {
      "unit_name": "Unit–VII Dual Nature of Radiation and Matter",
      "chapter_name": "Chapter–11: Dual Nature of Radiation and Matter",
      "topic": "Dual Nature of Radiation and Matter",
      "outcomes": [
        "Explain the experimental evidence for the particle nature of light (photoelectric effect)."
      ]
    },
    {
      "unit_name": "Unit–VIII Atoms and Nuclei",
      "chapter_name": "Chapter–12: Atoms",
      "topic": "Atomic Structure and Nuclear Physics",
      "outcomes": [
        "Describe the Bohr model of the atom including quantization of orbits."
      ]
    },
    {
      "unit_name": "Unit–IX Electronic Devices",
      "chapter_name": "Chapter–14: Semiconductor Electronics: Materials, Devices and Simple Circuits",
      "topic": "Semiconductor Electronics",
      "outcomes": [
        "Analyze the I-V characteristics of a semiconductor diode in forward and reverse bias."
      ]
    }
  ]
}
